<?php
namespace Tests\Feature;use App\Domain\Hunts\HuntService;use App\Models\Character;use App\Models\Hunt;use App\Models\HuntCombatEvent;use App\Models\User;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class HuntCombatEventTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);CarbonImmutable::setTestNow('2026-07-12 12:00:00');}protected function tearDown():void{CarbonImmutable::setTestNow();parent::tearDown();}public function test_events_and_playback_snapshot_are_persisted_authoritatively(){$character=Character::factory()->for(User::factory())->create(['base_attack'=>30]);$zone=Zone::where('code','grey_oak_forest')->firstOrFail();$result=app(HuntService::class)->start($character,$zone);$hunt=Hunt::with('combatEvents')->findOrFail($result->huntId());$this->assertGreaterThan(0,$hunt->combatEvents->count());$offset=0;foreach($hunt->combatEvents as $index=>$event){$this->assertSame($index+1,$event->sequence);$this->assertSame($offset,$event->playback_offset_ms);$this->assertNotSame($event->actor_identifier,$event->target_identifier);$this->assertSame(max(0,$event->target_health_before-$event->damage),$event->target_health_after);if(!$event->did_hit){$this->assertSame(0,$event->damage);$this->assertFalse($event->is_critical);$this->assertSame($event->target_health_before,$event->target_health_after);}$offset+=$event->playback_duration_ms;}$this->assertSame($offset,$hunt->combat_events_duration_ms);$this->assertSame($offset+$hunt->result_reveal_duration_ms+$hunt->loot_reveal_duration_ms,$hunt->playback_duration_ms);$this->assertSame(10000,$hunt->playback_speed_multiplier);$this->assertCount($hunt->combatEvents->count(),$result->events());}}
